<div class="sales-grid"><article class="sales-card span-5"><h2>Tambah Follow-up</h2><form class="sales-form" action="<?= app_url('sales/followups'); ?>" method="POST"><div class="sales-field"><label>Lead</label><select name="lead_id"><option value="">Tanpa lead</option><?php foreach($leads as $l): ?><option value="<?= (int)$l['id']; ?>"><?= htmlspecialchars($l['company_name']); ?></option><?php endforeach; ?></select></div><div class="sales-field"><label>Opportunity</label><select name="opportunity_id"><option value="">Tanpa opportunity</option><?php foreach($opportunities as $o): ?><option value="<?= (int)$o['id']; ?>"><?= htmlspecialchars($o['title']); ?></option><?php endforeach; ?></select></div><div class="sales-field"><label>Type</label><select name="activity_type"><?php foreach(['call','meeting','email','whatsapp','document_review'] as $t): ?><option value="<?= $t; ?>"><?= sales_label($t); ?></option><?php endforeach; ?></select></div><div class="sales-field"><label>Activity Date</label><input name="activity_date" type="date" value="<?= date('Y-m-d'); ?>" required></div><div class="sales-field full"><label>Result</label><input name="result"></div><div class="sales-field full"><label>Next Action</label><input name="next_action"></div><div class="sales-field"><label>Next Follow-up</label><input name="next_followup_date" type="date"></div><div class="sales-field"><label>Assigned</label><select name="assigned_user_id"><option value="">Unassigned</option><?php foreach($users as $u): ?><option value="<?= (int)$u['id']; ?>"><?= htmlspecialchars($u['full_name'] ?: $u['username']); ?></option><?php endforeach; ?></select></div><div class="sales-field full"><label>Notes</label><textarea name="notes"></textarea></div><div class="sales-field full"><button class="sales-btn" type="submit"><i class="bi bi-save"></i> Simpan Follow-up</button></div></form></article><article class="sales-card span-7"><h2>Daftar Follow-ups</h2><div class="sales-table-wrap"><table class="sales-table"><thead><tr><th>Target</th><th>Type</th><th>Date</th><th>Result</th><th>Next</th><th>Assigned</th><th></th></tr></thead><tbody><?php foreach($rows as $row): ?><tr><td><strong><?= htmlspecialchars($row['company_name'] ?: $row['opportunity_title'] ?: '-'); ?></strong></td><td><span class="sales-pill"><?= sales_label($row['activity_type']); ?></span></td><td><?= sales_date($row['activity_date']); ?></td><td><?= htmlspecialchars($row['result']); ?></td><td><?= sales_date($row['next_followup_date']); ?><br><span><?= htmlspecialchars($row['next_action']); ?></span></td><td><?= htmlspecialchars($row['assigned_name'] ?? '-'); ?></td><td class="sales-row-actions"><a class="sales-edit" href="<?= app_url('sales/followups/edit/'.(int)$row['id']); ?>"><i class="bi bi-pencil-square"></i></a><form action="<?= app_url('sales/followups/delete/'.(int)$row['id']); ?>" method="POST" onsubmit="return confirm('Hapus follow-up ini?');"><button class="sales-delete" type="submit"><i class="bi bi-trash"></i></button></form></td></tr><?php endforeach; ?></tbody></table></div></article></div></section></main><footer class="app-footer"><span>&copy; <?= date('Y'); ?> NovaTrack Riksa</span><span class="app-footer-sep">|</span><span>Sales</span></footer></body></html>
